// For each element, find the NEXT element to its right that's greater than it (or -1 if none)
vector<int> numbers = {2, 1, 2, 4, 3};
// answer:                {4, 2, 4, -1, -1}

for (int i = 0; i < numbers.size(); i++)
{
    for (int j = i + 1; j < numbers.size(); j++) // scan RIGHT for every element
    {
        if (numbers[j] > numbers[i]) { /* found it */ break; }
    }
}

#include <iostream>
#include <vector>
#include <stack>

using namespace std;

int main()
{
    vector<int> numbers = {2, 1, 2, 4, 3};
    vector<int> result(numbers.size(), -1);
    stack<int> indices; // stores INDICES, kept so their values are decreasing top-to-bottom

    for (int i = 0; i < numbers.size(); i++)
    {
        while (!indices.empty() && numbers[indices.top()] < numbers[i])
        {
            result[indices.top()] = numbers[i]; // numbers[i] IS the next greater element
            indices.pop();
        }
        indices.push(i);
    }

    for (int val : result)
    {
        cout << val << " ";
    }

    return 0;
}

