#include <iostream>
#include <vector>

using namespace std;

vector<int> nextGreaterElement(vector<int> &nums1, vector<int> &nums2)
{
    vector<int> result;

    for (int target : nums1)
    {
        int pos = 0;
        while (nums2[pos] != target) pos++;

        int answer = -1;
        for (int j = pos + 1; j < nums2.size(); j++)
        {
            if (nums2[j] > target) { answer = nums2[j]; break; }
        }
        result.push_back(answer);
    }

    return result;
}

int main()
{
    vector<int> nums1 = {4, 1, 2};
    vector<int> nums2 = {1, 3, 4, 2};

    vector<int> result = nextGreaterElement(nums1, nums2);
    for (int r : result) cout << r << " ";

    return 0;
}

#include <iostream>
#include <vector>
#include <stack>
#include <unordered_map>

using namespace std;

vector<int> nextGreaterElement(vector<int> &nums1, vector<int> &nums2)
{
    unordered_map<int, int> nextGreater;
    stack<int> pending;

    for (int num : nums2)
    {
        while (!pending.empty() && pending.top() < num)
        {
            nextGreater[pending.top()] = num;
            pending.pop();
        }
        pending.push(num);
    }

    vector<int> result;
    for (int target : nums1)
    {
        result.push_back(nextGreater.count(target) ? nextGreater[target] : -1);
    }

    return result;
}

int main()
{
    vector<int> nums1 = {4, 1, 2};
    vector<int> nums2 = {1, 3, 4, 2};

    vector<int> result = nextGreaterElement(nums1, nums2);
    for (int r : result) cout << r << " ";

    return 0;
}

